const Home = React.lazy(() => {
  return new Promise(resolve => {
    setTimeout(() => resolve(import("./Component/Home")), 2000);
  });
});

export default function App() {  
  return (
    <Suspense fallback={ <Loading /> }>
       <Home />
    </Suspense>
  )
}